let shuffleArray (nums: int list) (n: int) =
    // Split the list into two halves
    let firstHalf = nums.[..n-1]
    let secondHalf = nums.[n..]

    // Interleave the elements from the two halves
    let rec interleave acc first second =
        match first, second with
        | [], [] -> List.rev acc
        | x::xs, y::ys -> interleave (y :: x :: acc) xs ys
        | _ -> failwith "The input list should have exactly 2n elements"

    interleave [] firstHalf secondHalf

