let longestConsecutiveSequence (numbers: int list) =
    // Step 1: Remove duplicates and sort the list
    let sortedNumbers = List.sort (List.distinct numbers)

    // Step 2: Initialize variables to track the longest consecutive sequence
    let mutable maxLength = 0
    let mutable currentLength = 1

    // Step 3: Iterate through the sorted list to find the longest consecutive sequence
    for i in 1 .. List.length sortedNumbers - 1 do
        if sortedNumbers.[i] = sortedNumbers.[i - 1] + 1 then
            // If the current number is consecutive to the previous one, increment the current length
            currentLength <- currentLength + 1
        elif sortedNumbers.[i] <> sortedNumbers.[i - 1] then
            // If the current number is not consecutive, update the maximum length if needed and reset the current length
            if currentLength > maxLength then
                maxLength <- currentLength
            currentLength <- 1

    // Final check to update the maximum length in case the longest sequence ends at the last element
    if currentLength > maxLength then
        maxLength <- currentLength

    // Return the length of the longest consecutive sequence
    maxLength

