let validateISBN (isbnInput: string) : string =
    // Remove separators and extract digits
    let digits = isbnInput |> Seq.filter Char.IsDigit |> Seq.map (fun c -> int c - int '0') |> Seq.toArray

    // Calculate the expected check digit
    let expectedCheckDigit =
        digits
        |> Array.mapi (fun i d -> (i + 1) * d)
        |> Array.sum
        |> fun sum -> sum % 11
        |> function
        | 10 -> 'X'
        | d -> char (d + int '0')

    // Extract the provided check digit
    let providedCheckDigit = digits.[9]

    // Compare the provided check digit with the expected check digit
    if providedCheckDigit = expectedCheckDigit then
        "Right"
    else
        // Create the correct ISBN with the correct check digit
        let correctISBN =
            isbnInput.Substring(0, 10) + string expectedCheckDigit
        correctISBN

// Example usage
