let calculateFinalScore (scores: int list) =
    if List.length scores <= 2 then
        // If there are 2 or fewer scores, return 0.00 as we can't remove both highest and lowest
        0.00
    else
        // Sort the scores
        let sortedScores = List.sort scores
        // Remove the highest and lowest scores
        let remainingScores = List.tail (List.rev sortedScores)
        // Calculate the average of the remaining scores
        let sum = List.sum remainingScores
        let count = List.length remainingScores
        // Return the average as a float with 2 decimal places
        (float sum) / (float count) |> System.Math.Round |> fun x -> x * 100.0 / 100.0

