let finalPosition (commands: string) (time: int) : (int * int) =
    // Define the direction mapping
    let directionMap = 
        ['E', (1, 0)]
        ['S', (0, -1)]
        ['W', (-1, 0)]
        ['N', (0, 1)]

    // Initialize the starting position
    let mutable x, y = 0, 0

    // Loop through the commands for the given duration
    for i in 0 .. time - 1 do
        let command = commands.[i % commands.Length]
        match directionMap.[command] with
        | (dx, dy) -> x <- x + dx; y <- y + dy

    // Return the final position
    (x, y)

